module top_module(
    input clk,
    input in,
    input reset,
    output reg out
);     // State Encoding
    parameter A = 0, B = 1, C = 2, D = 3;
    reg [1:0] obf_state, next;

    // State Transition Logic
    always @(*) begin
        case (obf_state)
            A: next = in ? C : A;
            B: next = in ? A : C;
            C: next = in ? A : A;
            D: next = in ? C : B;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) obf_state <= A;
        else obf_state <= next;
    end

    // Output Logic
    always @(*) begin
        case (obf_state)
            A: out = 1;
            B: out = 1;
            C: out = 0;
            D: out = 1;
        endcase
    end
endmodule
